#!/usr/bin/env python3
from __future__ import annotations
"""Install DMoC module debug lab files."""
from pathlib import Path
import sys

def find_repo_root() -> Path:
    here = Path(__file__).resolve()
    for candidate in [here.parent, *here.parents]:
        if (candidate / "src").exists() and ((candidate / ".git").exists() or (candidate / "config").exists()):
            return candidate
    return Path.cwd().resolve()

ROOT = find_repo_root()
FILES = {}
FILES['scripts/module_lab/module_fixture_factory.py'] = 'from __future__ import annotations\n\n"""\nShared tensor fixtures for DMoC module debug labs.\n\nThe goal is to debug modules in isolation without MuJoCo:\n    fake inputs -> module -> output contract -> behavior checks.\n"""\n\nfrom dataclasses import dataclass\nfrom typing import Any, Dict, Optional\n\nimport torch\n\n\nDEFAULT_DEVICE = torch.device("cpu")\n\n\ndef seed_all(seed: int = 7) -> None:\n    torch.manual_seed(int(seed))\n\n\ndef finite_tensor(x: torch.Tensor) -> bool:\n    return torch.is_tensor(x) and bool(torch.isfinite(x).all().item())\n\n\ndef assert_tensor(name: str, value: Any, shape: Optional[tuple[int, ...]] = None) -> None:\n    assert torch.is_tensor(value), f"{name} must be a torch.Tensor, got {type(value)!r}"\n    assert finite_tensor(value), f"{name} contains NaN/Inf"\n    if shape is not None:\n        assert tuple(value.shape) == tuple(shape), f"{name} shape {tuple(value.shape)} != {shape}"\n\n\ndef assert_gate(name: str, value: Any, min_value: float = 0.0, max_value: float = 1.0) -> None:\n    assert_tensor(name, value)\n    vmin = float(value.detach().float().min().cpu().item())\n    vmax = float(value.detach().float().max().cpu().item())\n    assert vmin >= min_value - 1e-6, f"{name} min {vmin} < {min_value}"\n    assert vmax <= max_value + 1e-6, f"{name} max {vmax} > {max_value}"\n\n\ndef randn(batch: int = 1, dim: int = 256, scale: float = 0.25, device: torch.device | str = DEFAULT_DEVICE) -> torch.Tensor:\n    return torch.randn(batch, dim, device=device) * float(scale)\n\n\ndef scalar(value: float, device: torch.device | str = DEFAULT_DEVICE) -> torch.Tensor:\n    return torch.tensor([[float(value)]], dtype=torch.float32, device=device)\n\n\ndef make_fake_obs(\n    *,\n    batch: int = 1,\n    image_h: int = 32,\n    image_w: int = 48,\n    tactile_dim: int = 16,\n    body_state_dim: int = 32,\n    hand_motor_dim: int = 8,\n    embodied_dim: int = 15,\n    device: torch.device | str = DEFAULT_DEVICE,\n) -> Dict[str, torch.Tensor]:\n    seed_all()\n    return {\n        "left": torch.rand(batch, 3, image_h, image_w, device=device),\n        "right": torch.rand(batch, 3, image_h, image_w, device=device),\n        "depth": torch.rand(batch, 1, image_h, image_w, device=device),\n        "pose": randn(batch, 7, device=device),\n        "body_state": randn(batch, body_state_dim, device=device),\n        "tactile": randn(batch, tactile_dim, scale=0.10, device=device),\n        "hand_motor": randn(batch, hand_motor_dim, scale=0.10, device=device),\n        "embodied_action": randn(batch, embodied_dim, scale=0.10, device=device),\n        "object_state": randn(batch, 9, scale=0.10, device=device),\n        "reward": scalar(0.0, device=device),\n        "done": scalar(0.0, device=device),\n    }\n\n\ndef make_fake_m5_out(\n    *,\n    batch: int = 1,\n    focus_dim: int = 256,\n    workspace_dim: int = 256,\n    object_dim: int = 128,\n    thought_dim: int = 192,\n    memory_dim: int = 256,\n    coherence: float = 0.55,\n    curiosity: float = 0.45,\n    device: torch.device | str = DEFAULT_DEVICE,\n) -> Dict[str, Any]:\n    seed_all()\n    focus_context = randn(batch, focus_dim, device=device)\n    workspace_out = randn(batch, workspace_dim, device=device)\n    object_repr = randn(batch, object_dim, device=device)\n    thought_candidate = randn(batch, thought_dim, device=device)\n    memory_context = randn(batch, memory_dim, device=device)\n\n    return {\n        "focus_context": focus_context,\n        "workspace_out": workspace_out,\n        "object_repr": object_repr,\n        "object_imagery": {\n            "object_confidence": scalar(0.62, device=device),\n        },\n        "preconscious_thoughts": {\n            "thought_candidate": thought_candidate,\n            "workspace_seed": randn(batch, thought_dim, device=device),\n            "candidate_delta": randn(batch, thought_dim, scale=0.05, device=device),\n        },\n        "preconscious_reflection_out": {\n            "reflection": randn(batch, 128, device=device),\n            "model_confidence": scalar(0.58, device=device),\n        },\n        "memory": {\n            "memory_context": memory_context,\n        },\n        "values": {\n            "coherence": scalar(coherence, device=device),\n            "curiosity": scalar(curiosity, device=device),\n            "value_latent": randn(batch, 64, device=device),\n        },\n        "focus": {\n            "focus_idx": torch.zeros(batch, dtype=torch.long, device=device),\n        },\n        "action_logits": randn(batch, 8, device=device),\n        "action_ids": torch.zeros(batch, dtype=torch.long, device=device),\n        "embodied_targets": randn(batch, 15, scale=0.05, device=device),\n        "hand_ctrl": randn(batch, 8, scale=0.05, device=device),\n        "imagined": {\n            "imagined_value": scalar(0.15, device=device),\n            "imagined_touch": randn(batch, 16, scale=0.05, device=device),\n        },\n    }\n\n\ndef make_fake_affect(\n    *,\n    panic: float = 0.30,\n    stress: float = 0.25,\n    curiosity: float = 0.70,\n    expected_delta: float = 0.10,\n    device: torch.device | str = DEFAULT_DEVICE,\n) -> Dict[str, torch.Tensor]:\n    return {\n        "affect_latents": torch.tensor(\n            [[0.10, 0.50, 0.05, stress, 0.10, panic, 0.35, 0.25, curiosity, 0.40, 0.55, expected_delta]],\n            dtype=torch.float32,\n            device=device,\n        ),\n        "valence": scalar(0.10, device=device),\n        "arousal": scalar(0.50, device=device),\n        "panic_latent": scalar(panic, device=device),\n        "stress_latent": scalar(stress, device=device),\n        "curiosity_latent": scalar(curiosity, device=device),\n        "comfort_latent": scalar(0.35, device=device),\n        "relief_latent": scalar(0.25, device=device),\n        "expected_affect_delta": scalar(expected_delta, device=device),\n        "intrinsic_reward": scalar(0.02, device=device),\n    }\n\n\ndef make_fake_m13_memory(\n    *,\n    batch: int = 1,\n    dim: int = 256,\n    relevance: float = 0.55,\n    device: torch.device | str = DEFAULT_DEVICE,\n) -> Dict[str, Any]:\n    return {\n        "retrieved_context": randn(batch, dim, device=device),\n        "retrieval_relevance": scalar(relevance, device=device),\n        "retrieved_episode_count": scalar(3.0, device=device),\n        "summary": "fake autobiographical episode",\n    }\n\n\ndef make_fake_m4_identity(\n    *,\n    batch: int = 1,\n    dim: int = 256,\n    stability: float = 0.70,\n    novelty: float = 0.20,\n    gate: float = 0.80,\n    device: torch.device | str = DEFAULT_DEVICE,\n) -> Dict[str, Any]:\n    return {\n        "dynamic_identity_context": randn(batch, dim, device=device),\n        "dynamic_memory_gate": scalar(gate, device=device),\n        "identity_token": "obj:test",\n        "identity_stability": scalar(stability, device=device),\n        "identity_similarity": scalar(1.0 - novelty, device=device),\n        "identity_novelty": scalar(novelty, device=device),\n        "passport_slot": scalar(1.0, device=device),\n        "selected_sentence": "same object identity",\n    }\n\n\ndef make_fake_inner_object(\n    *,\n    batch: int = 1,\n    obj_dim: int = 128,\n    device: torch.device | str = DEFAULT_DEVICE,\n) -> Dict[str, Any]:\n    return {\n        "z_obj": randn(batch, obj_dim, device=device),\n        "slot_token": "slot:test",\n        "object_confidence": scalar(0.65, device=device),\n    }\n\n\nclass FakePassportManager:\n    """Minimal fake for LongDynamicMemory tests."""\n\n    def __init__(self, context_dim: int = 256, device: torch.device | str = DEFAULT_DEVICE) -> None:\n        self.context_dim = int(context_dim)\n        self.device = torch.device(device)\n        self.passports = {\n            "obj:test": {\n                "token": "obj:test",\n                "replay_z": randn(1, self.context_dim, device=self.device),\n                "confidence_ema": 0.72,\n                "last_similarity": 0.82,\n                "dynamic_score_ema": 0.35,\n                "lives_in_slot": 1,\n                "last_sentence": "same object identity",\n                "episode_summary": "fake passport episode",\n            }\n        }\n\n    def observe(self, obj: Dict[str, Any], *, event_memory=None, dream_mode: bool = False, global_step: int = 0) -> Dict[str, Any]:\n        del obj, event_memory, dream_mode, global_step\n        return {\n            "passport_token": "obj:test",\n            "passport_confidence_ema": 0.72,\n            "passport_similarity": 0.82,\n            "passport_dynamic_score": 0.35,\n            "passport_count": float(len(self.passports)),\n            "passport_slot": 1.0,\n            "passport_created": False,\n            "passport_sentence": "same object identity",\n            "passport_episode_summary": "fake passport episode",\n            "passport_source": "fake_passport",\n        }\n\n    def select_for_replay(self, token: str = "") -> Dict[str, Any]:\n        return self.passports.get(token or "obj:test", self.passports["obj:test"])\n\n\ndef make_fake_event_memory() -> list[Dict[str, Any]]:\n    return [\n        {\n            "sentence": "contact with object changed prediction",\n            "kind": "contact_prediction_delta",\n            "delta_norm": 0.75,\n            "contact_norm": 0.55,\n            "action_norm": 0.25,\n            "touch_strength": 0.50,\n            "event_code": torch.tensor([[0.75, 0.55, 0.25, 0.50, 0.10, 0.20, 0.30, 0.40]], dtype=torch.float32),\n        }\n    ]\n\n\ndef make_unconscious_loop_out(device: torch.device | str = DEFAULT_DEVICE) -> Dict[str, Any]:\n    out = make_fake_m5_out(device=device)\n    out["affect"] = make_fake_affect(device=device)\n    out["autobiographical_memory"] = make_fake_m13_memory(device=device)\n    out["long_dynamic_memory"] = make_fake_m4_identity(device=device)\n    return out\n'
FILES['scripts/module_lab/run_module_lab.py'] = 'from __future__ import annotations\n\n"""\nRun DMoC module lab without MuJoCo.\n\nExamples:\n    python scripts/module_lab/run_module_lab.py --module all\n    python scripts/module_lab/run_module_lab.py --module m02\n    python scripts/module_lab/run_module_lab.py --module loop\n"""\n\nimport argparse\nimport json\nfrom typing import Any, Dict\n\nimport torch\n\nfrom scripts.module_lab.module_fixture_factory import (\n    FakePassportManager,\n    assert_gate,\n    assert_tensor,\n    make_fake_affect,\n    make_fake_event_memory,\n    make_fake_inner_object,\n    make_fake_m13_memory,\n    make_fake_m4_identity,\n    make_fake_m5_out,\n    make_unconscious_loop_out,\n    scalar,\n)\n\n\ndef f(x: Any) -> float:\n    if torch.is_tensor(x):\n        return float(x.detach().reshape(-1)[0].cpu().item())\n    try:\n        return float(x)\n    except Exception:\n        return 0.0\n\n\ndef lab_m11() -> Dict[str, Any]:\n    from src.modules.m11_motivational_homeostasis.emotional_drive_bivalent import EmotionalDrive, EmotionalDriveConfig\n\n    out = make_fake_m5_out(coherence=0.75, curiosity=0.55)\n    obs = {"tactile": torch.ones(1, 16) * 0.05}\n    m11 = EmotionalDrive(EmotionalDriveConfig())\n    emotion = m11.compute(out, obs)\n\n    assert "affect" in emotion\n    affect = emotion["affect"]\n    for key in ("affect_latents", "valence", "arousal", "stress_latent", "panic_latent", "curiosity_latent", "comfort_latent", "relief_latent", "expected_affect_delta", "intrinsic_reward"):\n        assert key in affect, f"M11 affect missing {key}"\n        assert_tensor(f"M11 affect.{key}", affect[key])\n\n    return {\n        "module": "M11",\n        "valence": emotion["emotional_valence"],\n        "arousal": emotion["emotional_arousal"],\n        "stress": f(affect["stress_latent"]),\n        "panic": f(affect["panic_latent"]),\n        "curiosity": f(affect["curiosity_latent"]),\n        "status": "ok",\n    }\n\n\ndef lab_m13() -> Dict[str, Any]:\n    from src.modules.m13_autobiographical_memory.autobiographical_memory import AutobiographicalMemory, AutobiographicalMemoryConfig\n\n    out = make_fake_m5_out()\n    out["affect"] = make_fake_affect()\n\n    m13 = AutobiographicalMemory(AutobiographicalMemoryConfig(memory_dim=256, max_episodes=16, retrieval_topk=1))\n    empty = m13.retrieve(out)\n    assert_tensor("M13 empty.retrieved_context", empty["retrieved_context"], (1, 256))\n\n    m13.write_episode(obs={}, out=out, global_step=1)\n    got = m13.retrieve(out)\n    assert_tensor("M13 retrieved_context", got["retrieved_context"], (1, 256))\n    assert_gate("M13 retrieval_relevance", got["retrieval_relevance"], -1.0, 1.0)\n\n    return {\n        "module": "M13",\n        "episode_count": f(got["retrieved_episode_count"]),\n        "retrieval_relevance": f(got["retrieval_relevance"]),\n        "summary": got.get("summary", ""),\n        "status": "ok",\n    }\n\n\ndef lab_m4() -> Dict[str, Any]:\n    from src.modules.m04_long_dynamic_memory.long_dynamic_memory import LongDynamicMemory, LongDynamicMemoryConfig\n\n    out = make_fake_m5_out()\n    obj = make_fake_inner_object()\n    passport = FakePassportManager(context_dim=256)\n    m4 = LongDynamicMemory(LongDynamicMemoryConfig(context_dim=256))\n\n    packet = m4.compute(out=out, obj=obj, passport_manager=passport, event_memory=None, dream_mode=True, global_step=1)\n    assert_tensor("M4 dynamic_identity_context", packet["dynamic_identity_context"], (1, 256))\n    assert_gate("M4 dynamic_memory_gate", packet["dynamic_memory_gate"], 0.0, 1.0)\n    assert "identity_token" in packet\n\n    return {\n        "module": "M4",\n        "identity_token": packet.get("identity_token"),\n        "dynamic_memory_gate": f(packet["dynamic_memory_gate"]),\n        "identity_stability": f(packet["identity_stability"]),\n        "identity_novelty": f(packet["identity_novelty"]),\n        "status": "ok",\n    }\n\n\ndef lab_m02() -> Dict[str, Any]:\n    from src.modules.m02_event_dream_replay.event_dream_replay import EventDreamReplay, EventDreamReplayConfig\n\n    cfg = EventDreamReplayConfig(\n        replay_context_dim=256,\n        event_code_dim=8,\n        blend_replay_into_focus=False,\n        use_m13_context=True,\n        use_m4_context=True,\n        seed_to_m5_boundary=True,\n    )\n    m2 = EventDreamReplay(cfg)\n    out = make_unconscious_loop_out()\n    packet = m2.compute(out=out, event_memory=make_fake_event_memory(), dream_mode=True)\n\n    assert_tensor("M2 replay_context", packet["replay_context"], (1, 256))\n    assert_gate("M2 replay_gate", packet["replay_gate"], 0.0, 1.0)\n    assert_gate("M2 dream_pressure", packet["dream_pressure"], 0.0, 1.0)\n    assert "selected_identity_token" in packet\n\n    return {\n        "module": "M2",\n        "replay_gate": f(packet["replay_gate"]),\n        "dream_pressure": f(packet["dream_pressure"]),\n        "event_salience": f(packet["event_salience"]),\n        "should_replay": f(packet["should_replay"]),\n        "source": packet.get("replay_source", ""),\n        "identity": packet.get("selected_identity_token", ""),\n        "status": "ok",\n    }\n\n\ndef lab_m05_boundary() -> Dict[str, Any]:\n    from src.modules.m05_world_model_attention_workspace.models.focus_feedback_boundary import FocusFeedbackBoundary\n\n    b = 1\n    boundary = FocusFeedbackBoundary(focus_context_dim=256, workspace_seed_dim=256, thought_dim=192)\n    workspace_seed = torch.randn(b, 256)\n    focus_seed = torch.randn(b, 256)\n    gate = torch.tensor([[0.1]])\n\n    packet = boundary(\n        workspace_seed=workspace_seed,\n        focus_context_seed=focus_seed,\n        focus_context_seed_gate=gate,\n    )\n\n    assert_tensor("M5Boundary workspace_seed", packet["workspace_seed"], (b, 256))\n    assert_tensor("M5Boundary preconscious_delta", packet["preconscious_delta"], (b, 192))\n    assert_gate("M5Boundary total_gate", packet["total_gate"], 0.0, 0.35)\n\n    pre = torch.randn(b, 192)\n    pre2 = boundary.apply_preconscious_seed(pre, packet)\n    assert_tensor("M5Boundary applied_preconscious", pre2, (b, 192))\n\n    changed = float((packet["workspace_seed"] - workspace_seed).abs().mean().detach().cpu().item())\n\n    return {\n        "module": "M5 FocusFeedbackBoundary",\n        "total_gate": f(packet["total_gate"]),\n        "learned_gate": f(packet["learned_gate"]),\n        "workspace_delta_mean_abs": changed,\n        "status": "ok",\n    }\n\n\ndef lab_loop() -> Dict[str, Any]:\n    """Contract test for M11 + M13 + M4 + M2 + M5 boundary."""\n    m11 = lab_m11()\n    m13 = lab_m13()\n    m4 = lab_m4()\n    m2 = lab_m02()\n    m5b = lab_m05_boundary()\n\n    assert m2["replay_gate"] >= 0.0\n    assert m5b["total_gate"] >= 0.0\n\n    return {\n        "module": "unconscious_loop",\n        "chain": "M1 -> M5 -> M11 -> M2 -> FocusFeedbackBoundary -> M5; M4/M13 -> M2; M5 -> M3",\n        "m11": m11,\n        "m13": m13,\n        "m4": m4,\n        "m2": m2,\n        "m5_boundary": m5b,\n        "status": "ok",\n    }\n\n\nLABS = {\n    "m11": lab_m11,\n    "m13": lab_m13,\n    "m4": lab_m4,\n    "m02": lab_m02,\n    "m2": lab_m02,\n    "m05": lab_m05_boundary,\n    "m5": lab_m05_boundary,\n    "boundary": lab_m05_boundary,\n    "loop": lab_loop,\n}\n\n\ndef main() -> None:\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--module", default="all", choices=["all", *LABS.keys()])\n    parser.add_argument("--json", action="store_true")\n    args = parser.parse_args()\n\n    if args.module == "all":\n        result = {name: func() for name, func in LABS.items() if name in ("m11", "m13", "m4", "m02", "m05", "loop")}\n    else:\n        result = LABS[args.module]()\n\n    if args.json:\n        print(json.dumps(result, ensure_ascii=False, indent=2))\n    else:\n        print(json.dumps(result, ensure_ascii=False, indent=2))\n\n\nif __name__ == "__main__":\n    main()\n'
FILES['tests/module_contracts/test_m05_focus_feedback_boundary_contract.py'] = 'from __future__ import annotations\n\nimport torch\n\nfrom scripts.module_lab.module_fixture_factory import assert_gate, assert_tensor\n\n\ndef test_m05_focus_feedback_boundary_contract():\n    from src.modules.m05_world_model_attention_workspace.models.focus_feedback_boundary import FocusFeedbackBoundary\n\n    boundary = FocusFeedbackBoundary(focus_context_dim=256, workspace_seed_dim=256, thought_dim=192)\n\n    workspace_seed = torch.randn(1, 256)\n    focus_seed = torch.randn(1, 256)\n    gate = torch.tensor([[0.2]])\n\n    packet = boundary(\n        workspace_seed=workspace_seed,\n        focus_context_seed=focus_seed,\n        focus_context_seed_gate=gate,\n    )\n\n    for key in ("active", "workspace_seed", "external_gate", "learned_gate", "total_gate", "workspace_delta", "preconscious_delta", "seed_norm"):\n        assert key in packet, f"missing {key}"\n\n    assert_tensor("workspace_seed", packet["workspace_seed"], (1, 256))\n    assert_tensor("preconscious_delta", packet["preconscious_delta"], (1, 192))\n    assert_gate("total_gate", packet["total_gate"], 0.0, 0.35)\n\n    pre = torch.randn(1, 192)\n    pre2 = boundary.apply_preconscious_seed(pre, packet)\n    assert_tensor("pre2", pre2, (1, 192))\n\n\ndef test_m05_focus_feedback_boundary_zero_gate_no_runaway():\n    from src.modules.m05_world_model_attention_workspace.models.focus_feedback_boundary import FocusFeedbackBoundary\n\n    boundary = FocusFeedbackBoundary(focus_context_dim=256, workspace_seed_dim=256, thought_dim=192)\n\n    workspace_seed = torch.randn(1, 256)\n    packet = boundary(\n        workspace_seed=workspace_seed,\n        focus_context_seed=None,\n        focus_context_seed_gate=None,\n    )\n\n    assert torch.allclose(packet["workspace_seed"], workspace_seed)\n    assert float(packet["total_gate"].detach().cpu().item()) == 0.0\n'
FILES['tests/module_contracts/test_m02_event_dream_replay_contract.py'] = 'from __future__ import annotations\n\nimport torch\n\nfrom scripts.module_lab.module_fixture_factory import (\n    assert_gate,\n    assert_tensor,\n    make_fake_event_memory,\n    make_unconscious_loop_out,\n)\n\n\ndef test_m02_event_dream_replay_contract_with_m13_and_m4():\n    from src.modules.m02_event_dream_replay.event_dream_replay import EventDreamReplay, EventDreamReplayConfig\n\n    cfg = EventDreamReplayConfig(\n        replay_context_dim=256,\n        event_code_dim=8,\n        blend_replay_into_focus=False,\n        use_m13_context=True,\n        use_m4_context=True,\n        seed_to_m5_boundary=True,\n    )\n    m2 = EventDreamReplay(cfg)\n    out = make_unconscious_loop_out()\n\n    packet = m2.compute(out=out, event_memory=make_fake_event_memory(), dream_mode=True)\n\n    for key in ("replay_context", "replay_gate", "event_salience", "dream_pressure", "should_replay", "replay_source"):\n        assert key in packet, f"missing {key}"\n\n    assert_tensor("replay_context", packet["replay_context"], (1, 256))\n    assert_gate("replay_gate", packet["replay_gate"], 0.0, 1.0)\n    assert_gate("dream_pressure", packet["dream_pressure"], 0.0, 1.0)\n    assert_gate("should_replay", packet["should_replay"], 0.0, 1.0)\n\n    assert "selected_identity_token" in packet, "M2 must expose M4 identity token"\n    assert "dynamic_memory_gate" in packet, "M2 must expose M4 dynamic memory gate"\n\n\ndef test_m02_dream_pressure_increases_with_affect():\n    from src.modules.m02_event_dream_replay.event_dream_replay import EventDreamReplay, EventDreamReplayConfig\n\n    cfg = EventDreamReplayConfig(\n        replay_context_dim=256,\n        event_code_dim=8,\n        blend_replay_into_focus=False,\n        use_m13_context=True,\n        use_m4_context=True,\n        seed_to_m5_boundary=True,\n    )\n    m2 = EventDreamReplay(cfg)\n\n    low = make_unconscious_loop_out()\n    low["affect"]["panic_latent"] = torch.tensor([[0.0]])\n    low["affect"]["stress_latent"] = torch.tensor([[0.0]])\n    low_packet = m2.compute(out=low, event_memory=None, dream_mode=True)\n\n    high = make_unconscious_loop_out()\n    high["affect"]["panic_latent"] = torch.tensor([[0.9]])\n    high["affect"]["stress_latent"] = torch.tensor([[0.9]])\n    high_packet = m2.compute(out=high, event_memory=None, dream_mode=True)\n\n    assert float(high_packet["dream_pressure"].item()) >= float(low_packet["dream_pressure"].item())\n'
FILES['tests/module_contracts/test_m04_long_dynamic_memory_contract.py'] = 'from __future__ import annotations\n\nfrom scripts.module_lab.module_fixture_factory import (\n    FakePassportManager,\n    assert_gate,\n    assert_tensor,\n    make_fake_inner_object,\n    make_fake_m5_out,\n)\n\n\ndef test_m04_long_dynamic_memory_contract():\n    from src.modules.m04_long_dynamic_memory.long_dynamic_memory import LongDynamicMemory, LongDynamicMemoryConfig\n\n    m4 = LongDynamicMemory(LongDynamicMemoryConfig(context_dim=256))\n    out = make_fake_m5_out()\n    obj = make_fake_inner_object()\n    passport_manager = FakePassportManager(context_dim=256)\n\n    packet = m4.compute(\n        out=out,\n        obj=obj,\n        passport_manager=passport_manager,\n        event_memory=None,\n        dream_mode=True,\n        global_step=1,\n    )\n\n    for key in ("dynamic_identity_context", "dynamic_memory_gate", "identity_token", "identity_stability", "identity_novelty", "passport_slot", "selected_sentence"):\n        assert key in packet, f"missing {key}"\n\n    assert_tensor("dynamic_identity_context", packet["dynamic_identity_context"], (1, 256))\n    assert_gate("dynamic_memory_gate", packet["dynamic_memory_gate"], 0.0, 1.0)\n    assert packet["identity_token"] == "obj:test"\n'
FILES['tests/module_contracts/test_m13_autobiographical_memory_contract.py'] = 'from __future__ import annotations\n\nfrom scripts.module_lab.module_fixture_factory import assert_gate, assert_tensor, make_fake_affect, make_fake_m5_out\n\n\ndef test_m13_autobiographical_memory_empty_and_retrieval_contract():\n    from src.modules.m13_autobiographical_memory.autobiographical_memory import AutobiographicalMemory, AutobiographicalMemoryConfig\n\n    m13 = AutobiographicalMemory(AutobiographicalMemoryConfig(memory_dim=256, max_episodes=16, retrieval_topk=1))\n    out = make_fake_m5_out()\n    out["affect"] = make_fake_affect()\n\n    empty = m13.retrieve(out)\n    assert_tensor("empty retrieved_context", empty["retrieved_context"], (1, 256))\n    assert_gate("empty retrieval_relevance", empty["retrieval_relevance"], 0.0, 0.0)\n\n    m13.write_episode(obs={}, out=out, global_step=1)\n    got = m13.retrieve(out)\n\n    assert_tensor("retrieved_context", got["retrieved_context"], (1, 256))\n    assert_gate("retrieval_relevance", got["retrieval_relevance"], -1.0, 1.0)\n    assert "summary" in got\n'
FILES['tests/module_contracts/test_m11_emotional_drive_contract.py'] = 'from __future__ import annotations\n\nimport torch\n\nfrom scripts.module_lab.module_fixture_factory import assert_tensor, make_fake_m5_out\n\n\ndef test_m11_emotional_drive_affect_contract():\n    from src.modules.m11_motivational_homeostasis.emotional_drive_bivalent import EmotionalDrive, EmotionalDriveConfig\n\n    m11 = EmotionalDrive(EmotionalDriveConfig())\n    out = make_fake_m5_out(coherence=0.75, curiosity=0.60)\n    obs = {"tactile": torch.ones(1, 16) * 0.05}\n\n    emotion = m11.compute(out, obs)\n    assert "affect" in emotion\n    affect = emotion["affect"]\n\n    required = (\n        "affect_latents",\n        "valence",\n        "arousal",\n        "pain_latent",\n        "stress_latent",\n        "fear_latent",\n        "panic_latent",\n        "comfort_latent",\n        "relief_latent",\n        "curiosity_latent",\n        "discovery_latent",\n        "coherence_latent",\n        "expected_affect_delta",\n        "intrinsic_reward",\n    )\n    for key in required:\n        assert key in affect, f"missing affect.{key}"\n        assert_tensor(f"affect.{key}", affect[key])\n'
FILES['tests/module_contracts/test_unconscious_loop_contract.py'] = 'from __future__ import annotations\n\nimport torch\n\nfrom scripts.module_lab.module_fixture_factory import (\n    FakePassportManager,\n    assert_gate,\n    assert_tensor,\n    make_fake_event_memory,\n    make_fake_inner_object,\n    make_fake_m5_out,\n)\n\n\ndef test_unconscious_loop_contract_m11_m13_m4_m2_m5_boundary():\n    from src.modules.m02_event_dream_replay.event_dream_replay import EventDreamReplay, EventDreamReplayConfig\n    from src.modules.m04_long_dynamic_memory.long_dynamic_memory import LongDynamicMemory, LongDynamicMemoryConfig\n    from src.modules.m05_world_model_attention_workspace.models.focus_feedback_boundary import FocusFeedbackBoundary\n    from src.modules.m11_motivational_homeostasis.emotional_drive_bivalent import EmotionalDrive, EmotionalDriveConfig\n    from src.modules.m13_autobiographical_memory.autobiographical_memory import AutobiographicalMemory, AutobiographicalMemoryConfig\n\n    # Fake M5 output: M1 must not be fed to M2 directly in this contract.\n    out = make_fake_m5_out()\n    obs = {"tactile": torch.ones(1, 16) * 0.05}\n\n    # M11 evaluates M5 output.\n    m11 = EmotionalDrive(EmotionalDriveConfig())\n    emotion = m11.compute(out, obs)\n    out["emotion"] = emotion\n    out["affect"] = emotion["affect"]\n\n    # M13 retrieves episodic context.\n    m13 = AutobiographicalMemory(AutobiographicalMemoryConfig(memory_dim=256, max_episodes=16, retrieval_topk=1))\n    m13.write_episode(obs=obs, out=out, global_step=1)\n    out["autobiographical_memory"] = m13.retrieve(out)\n\n    # M4 derives object identity from inner_object/z_obj, not raw M1.\n    m4 = LongDynamicMemory(LongDynamicMemoryConfig(context_dim=256))\n    inner_object = make_fake_inner_object()\n    out["inner_object"] = inner_object\n    out["long_dynamic_memory"] = m4.compute(\n        out=out,\n        obj=inner_object,\n        passport_manager=FakePassportManager(context_dim=256),\n        event_memory=None,\n        dream_mode=True,\n        global_step=1,\n    )\n\n    # M2 selects replay context from M11 + M13 + M4 + current M5 focus.\n    m2 = EventDreamReplay(EventDreamReplayConfig(\n        replay_context_dim=256,\n        event_code_dim=8,\n        blend_replay_into_focus=False,\n        use_m13_context=True,\n        use_m4_context=True,\n        seed_to_m5_boundary=True,\n    ))\n    packet = m2.compute(out=out, event_memory=make_fake_event_memory(), dream_mode=True)\n\n    assert_tensor("M2 replay_context", packet["replay_context"], (1, 256))\n    assert_gate("M2 replay_gate", packet["replay_gate"], 0.0, 1.0)\n    assert "selected_identity_token" in packet\n    assert "selected_episode_summary" in packet\n\n    # M2 replay_context enters M5 only through FocusFeedbackBoundary.\n    boundary = FocusFeedbackBoundary(focus_context_dim=256, workspace_seed_dim=256, thought_dim=192)\n    workspace_seed = torch.randn(1, 256)\n    boundary_packet = boundary(\n        workspace_seed=workspace_seed,\n        focus_context_seed=packet["replay_context"],\n        focus_context_seed_gate=packet["replay_gate"],\n    )\n\n    assert_tensor("boundary workspace_seed", boundary_packet["workspace_seed"], (1, 256))\n    assert_tensor("boundary preconscious_delta", boundary_packet["preconscious_delta"], (1, 192))\n    assert_gate("boundary total_gate", boundary_packet["total_gate"], 0.0, 0.35)\n\n\ndef test_forbidden_direct_m1_to_m2_is_not_used_in_contract():\n    # The test intentionally builds M2 input from M5 out + M11/M13/M4,\n    # not from raw obs/M1. This is the architectural invariant.\n    from scripts.module_lab.module_fixture_factory import make_unconscious_loop_out\n    out = make_unconscious_loop_out()\n    assert "left" not in out\n    assert "right" not in out\n    assert "depth" not in out\n'
FILES['tests/module_contracts/test_m02_runtime_seed_bus_contract.py'] = 'from __future__ import annotations\n\nimport torch\n\nfrom scripts.module_lab.module_fixture_factory import assert_tensor, make_unconscious_loop_out\n\n\nclass DummyEventDreamRuntime:\n    """Small local object to test EventDreamReplayRuntimeMixin without full runner."""\n\n    from src.modules.m02_event_dream_replay.event_dream_runtime import EventDreamReplayRuntimeMixin\n\n    class Cfg:\n        class EventDreamReplay:\n            enabled = True\n            replay_context_dim = 256\n            event_code_dim = 8\n            replay_threshold = 0.35\n            focus_blend = 0.15\n            blend_replay_into_focus = False\n            use_m13_context = True\n            use_m4_context = True\n            m4_context_weight = 0.20\n            use_event_memory = False\n            max_recent_events_scan = 16\n            seed_to_m5_boundary = True\n            seed_gate_gain = 1.0\n            apply_stage = "pre_observe"\n            seed_only_in_sleep = True\n\n        event_dream_replay = EventDreamReplay()\n\n    cfg = Cfg()\n    device = torch.device("cpu")\n    event_latent_memory = None\n    global_step = 1\n\n    def is_full_sleep_mode(self):\n        return True\n\n    ensure_event_dream_replay_ready = EventDreamReplayRuntimeMixin.ensure_event_dream_replay_ready\n    compute_event_dream_replay = EventDreamReplayRuntimeMixin.compute_event_dream_replay\n    get_event_dream_focus_seed = EventDreamReplayRuntimeMixin.get_event_dream_focus_seed\n    get_m5_focus_seed = EventDreamReplayRuntimeMixin.get_m5_focus_seed\n    _store_event_dream_m5_seed = EventDreamReplayRuntimeMixin._store_event_dream_m5_seed\n    _event_dream_stage_allowed = EventDreamReplayRuntimeMixin._event_dream_stage_allowed\n\n\ndef test_m02_runtime_seed_bus_contract():\n    runtime = DummyEventDreamRuntime()\n    out = make_unconscious_loop_out()\n\n    packet = runtime.compute_event_dream_replay({}, out)\n    assert packet is not None\n    assert "event_dream_replay" in out\n\n    seed, gate = runtime.get_m5_focus_seed(stage="pre_observe")\n    assert_tensor("M2 seed", seed, (1, 256))\n    assert_tensor("M2 seed gate", gate)\n\n    # main stage is disabled by default in this contract.\n    seed2, gate2 = runtime.get_m5_focus_seed(stage="main")\n    assert seed2 is None and gate2 is None\n'
FILES['docs/architecture/module_debug_lab.md'] = '# DMoC module debug lab\n\nThis lab checks modules in isolation without MuJoCo.\n\n## Target unconscious loop\n\n```text\nM1 -> M5 -> M11 -> M2 -> M5 FocusFeedbackBoundary -> M5\n      |             ^\n      v             |\n     M4 ------------+\n                   M13 -> M2\n\nM5 -> M3 -> body/world -> M1\n```\n\nRules:\n\n- M1 does not feed M2 directly.\n- M2 does not mutate `out["focus_context"]` by default.\n- M2 sends `replay_context` to the same M5 seed input as M15:\n  `focus_context_seed` + `focus_context_seed_gate`.\n- M4 is derived from `inner_object / z_obj`, not raw sensors.\n- M13 feeds M2 with `retrieved_context`.\n- M11 feeds M2 with affect/emotional pressure.\n\n## Run all labs\n\n```bash\npython scripts/module_lab/run_module_lab.py --module all\n```\n\n## Run pytest contracts\n\n```bash\npytest tests/module_contracts\n```\n\n## Compile checks\n\n```bash\npython -m py_compile scripts/module_lab/module_fixture_factory.py\npython -m py_compile scripts/module_lab/run_module_lab.py\npython -m py_compile tests/module_contracts/test_m02_event_dream_replay_contract.py\npython -m py_compile tests/module_contracts/test_m02_runtime_seed_bus_contract.py\npython -m py_compile tests/module_contracts/test_m04_long_dynamic_memory_contract.py\npython -m py_compile tests/module_contracts/test_m05_focus_feedback_boundary_contract.py\npython -m py_compile tests/module_contracts/test_m11_emotional_drive_contract.py\npython -m py_compile tests/module_contracts/test_m13_autobiographical_memory_contract.py\npython -m py_compile tests/module_contracts/test_unconscious_loop_contract.py\n```\n'
FILES['README_module_debug_lab_patch_v1.md'] = '# module_debug_lab_patch_v1\n\nДобавляет лабораторию модулей для DMoC:\n\n```text\nscripts/module_lab/\ntests/module_contracts/\ndocs/architecture/module_debug_lab.md\n```\n\nУстановка:\n\n```bash\nunzip -o module_debug_lab_patch_v1.zip -d .\npython scripts/apply_module_debug_lab_patch_v1.py\n```\n\nПроверка:\n\n```bash\npython scripts/module_lab/run_module_lab.py --module all\npytest tests/module_contracts\n```\n\nГлавная проверяемая архитектура:\n\n```text\nM1 -> M5 -> M11 -> M2 -> FocusFeedbackBoundary -> M5\n      |             ^\n      v             |\n     M4 ------------+\n                   M13 -> M2\n\nM5 -> M3 -> тело/мир -> M1\n```\n'

def main() -> int:
    for rel, content in FILES.items():
        target = ROOT / rel
        target.parent.mkdir(parents=True, exist_ok=True)
        if target.exists() and target.read_text(encoding='utf-8') == content:
            print(f'[skip] {rel}: unchanged')
            continue
        target.write_text(content, encoding='utf-8')
        print(f'[ok] wrote {rel}')
    print('\nRun:')
    print('  python scripts/module_lab/run_module_lab.py --module all')
    print('  pytest tests/module_contracts')
    return 0

if __name__ == '__main__':
    try:
        raise SystemExit(main())
    except Exception as e:
        print(f'\n[ERROR] {e}', file=sys.stderr)
        raise
